function AdminPetManagement() {
    useEffect(() => {
        document.title = "MISHTIKA - Pet Management";
    }, []);

    const [pets, setPets] = useState([]);
    const [showModal, setShowModal] = useState(false);
    const [petToDelete, setPetToDelete] = useState(null);
    const [error, setError] = useState('');


    const fetchPets = async () => {
        setError('');
        try {
            const response = await api.get('/admin/pets');
            setPets(response.data);
        } catch (err) {
            setError('An error occurred while fetching pets.');
        }
    };

    useEffect(() => {
        fetchPets();
    }, []);

    const handleShowModal = (petId) => {
        setPetToDelete(petId);
        setShowModal(true);
    };

    const handleCloseModal = () => {
        setShowModal(false);
        setPetToDelete(null);
    };

    const handleDeletePet = async () => {
        if (!petToDelete) return;
        setError('');
        try {
            await api.delete(`/admin/pets/${petToDelete}`);
            setPets(pets.filter(p => p._id !== petToDelete));
            handleCloseModal();
        } catch (err) {
            setError('An error occurred while deleting pet.');
            handleCloseModal();
        }
    };

    return (
        <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="max-w-7xl mx-auto my-8 px-4 sm:px-6 space-y-6">

            <div className="flex items-center gap-3 mb-8">
                <div className="p-2 bg-primary/10 text-primary rounded-lg"><PawPrint size={24} /></div>
                <div>
                    <h1 className="text-3xl font-heading font-bold text-brandText">Pet Registry</h1>
                    <p className="text-sm text-brandText-muted">Database of all registered companions in the system.</p>
                </div>
            </div>

            {error && (
                <div className="p-4 mb-6 bg-red-50 text-red-600 rounded-xl flex items-center gap-3 font-medium text-sm border border-red-100">
                    <ShieldAlert size={18} /> {error}
                </div>
            )}

            {/* Tailwind Data Table */}
            <div className="bg-surface rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-gray-50/50 border-b border-gray-100">
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Pet Profile</th>
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Owner Account</th>
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Species & Breed</th>
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider">Age Tracking</th>
                                <th className="px-6 py-4 text-xs font-semibold text-gray-500 uppercase tracking-wider text-right">Actions</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {pets.length > 0 ? pets.map((pet) => (
                                <tr key={pet._id} className="hover:bg-gray-50/50 transition-colors">
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <span className="font-bold text-brandText text-lg font-heading">{pet.name}</span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <span className="text-sm text-brandText-muted">{pet.ownerName || 'Unassigned'}</span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="flex items-center gap-2">
                                            <span className={clsx("flex items-center justify-center p-1.5 rounded-md", pet.species === 'Cat' ? "bg-secondary/10 text-secondary" : "bg-primary/10 text-primary")}>
                                                {pet.species === 'Dog' ? <Dog size={16} /> : pet.species === 'Cat' ? <Cat size={16} /> : <PawPrint size={16} />}
                                            </span>
                                            <div>
                                                <div className="text-sm font-semibold text-brandText">{pet.species}</div>
                                                <div className="text-xs text-brandText-muted">{pet.breed}</div>
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <span className="inline-flex items-center px-2.5 py-1 rounded-full text-xs font-semibold bg-gray-100 text-gray-700">
                                            {pet.ageYears} yrs, {pet.ageMonths} mos
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-right">
                                        <div className="flex justify-end">
                                            <button 
                                                onClick={() => handleShowModal(pet._id)}
                                                className="px-3 py-1.5 bg-red-50 text-red-700 hover:bg-red-100 text-xs font-semibold rounded-lg flex items-center gap-1.5 transition-colors border border-red-200"
                                            >
                                                <Trash2 size={14} /> Delete Record
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            )) : (
                                <tr>
                                    <td colSpan="5" className="px-6 py-8 text-center text-brandText-muted">No pets registered in the system yet.</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Custom Tailwind Modal for Delete confirmation */}
            <AnimatePresence>
                {showModal && (
                    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4">
                        <motion.div initial={{ opacity: 0, scale: 0.95 }} animate={{ opacity: 1, scale: 1 }} exit={{ opacity: 0, scale: 0.95 }} className="bg-surface rounded-3xl p-6 shadow-xl w-full max-w-sm border border-gray-100">
                            <div className="w-12 h-12 rounded-full bg-red-100 text-red-600 flex items-center justify-center mb-4">
                                <AlertCircle size={24} />
                            </div>
                            <h2 className="text-xl font-heading font-bold text-brandText mb-2">Delete Pet Record?</h2>
                            <p className="text-brandText-muted mb-6">Are you sure you want to permanently delete this pet from the database? This action cannot be undone.</p>
                            <div className="flex gap-3 justify-end mt-4">
                                <button onClick={handleCloseModal} className="px-4 py-2 bg-gray-100 text-brandText font-semibold rounded-xl hover:bg-gray-200 transition-colors">
                                    Cancel
                                </button>
                                <button onClick={handleDeletePet} className="px-4 py-2 bg-red-500 text-white font-semibold rounded-xl hover:bg-red-600 shadow-sm transition-colors">
                                    Permanently Delete
                                </button>
                            </div>
                        </motion.div>
                    </div>
                )}
            </AnimatePresence>
        </motion.div>
    );
}

```
